#include<bits/stdc++.h>
using namespace std;
long long sum[500005];
int pos[10];
int ans;
int main()
{
	int n;
	cin>>n;
	
	memset(pos,-1,sizeof(pos));
    pos[0]=0;
	for(int i=1;i<=n;i++){
	    long long x;
		cin>>x;
		sum[i]=sum[i-1]+x;
		if(pos[sum[i]%7]==-1)
		    pos[sum[i]%7]=i;
		else ans=max(ans,i-pos[sum[i]%7]);
	}
	cout<<ans;
}
